def test_instruction_text_before_amendment_container_is_cached_by_source_element() -> None:
    element = ET.fromstring(
        """
        <P1>
          <Text>In section 1, after subsection (1) insert-</Text>
          <BlockAmendment><P2><Text>payload</Text></P2></BlockAmendment>
          <Text>tail ignored</Text>
        </P1>
        """
    )

    _INSTRUCTION_TEXT_CACHE.pop(element, None)
    assert _instruction_text_before_amendment_container(element) == "In section 1, after subsection (1) insert-"
    assert _INSTRUCTION_TEXT_CACHE[element] == "In section 1, after subsection (1) insert-"
    assert _instruction_text_before_amendment_container(element) == "In section 1, after subsection (1) insert-"


def test_get_id_sequence_preserves_hyphen_underscore_boundaries() -> None:
    assert _get_id_sequence("ukpga-1988_1-section_12A") == (
        "ukpga",
        "1988",
        "1",
        "section",
        "12",
        "a",
    )
    assert _get_id_sequence("part__iv--paragraph_3b") == (
        "part",
        "4",
        "paragraph",
        "3",
        "b",
    )


def test_first_component_matches_preserves_document_order_with_number_index() -> None:
    root = ET.fromstring(
        """
        <Body>
          <P1><Pnumber>7</Pnumber><Text>first section-like node</Text></P1>
          <P2><Pnumber>7</Pnumber><Text>wrong kind</Text></P2>
          <Section><Number>7</Number><Text>second section-like node</Text></Section>
          <P1group><Pnumber>7</Pnumber><Text>third section-like node</Text></P1group>
        </Body>
        """
    )

    matches = _first_component_matches(root, "section", "7")

    assert [element.tag for element in matches] == ["P1", "Section", "P1group"]
    assert [" ".join(element.itertext()).strip() for element in matches] == [
        "7 first section-like node",
        "7 second section-like node",
        "7 third section-like node",
    ]


def replay_uk_ops(base, ops, **kwargs):
    return UKReplayPipeline(Path(".")).apply_ops(base, ops, **kwargs)


def _replace_patch(match: str, replacement: str, occurrence: int = 0) -> TextPatchSpec:
    return TextPatchSpec(
        kind=TextPatchKindEnum.REPLACE,
        selector=TextSelector(match_text=match, occurrence=occurrence),
        replacement=replacement,
    )


def _append_patch(insertion: str) -> TextPatchSpec:
    return TextPatchSpec(
        kind=TextPatchKindEnum.APPEND,
        selector=TextSelector(match_text="TEXT_END", occurrence=0),
        replacement=insertion,
    )


def test_uk_grounding_length_window_candidates_preserve_oracle_order() -> None:
    candidates_by_len = {
        90: [(2, "too-short", "x" * 90)],
        95: [(1, "second", "x" * 95)],
        100: [(0, "first", "x" * 100)],
        111: [(3, "too-long", "x" * 111)],
    }

    assert _grounding_length_window_text_candidates(candidates_by_len, 100) == [
        ("first", "x" * 100),
        ("second", "x" * 95),
        ("too-short", "x" * 90),
    ]


