def test_executor_range_to_end_text_patch_records_node_local_leaf_rewrite() -> None:
    adjudications: list[CompileAdjudication] = []
    statute = IRStatute(
        statute_id="asp/2001/14",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="3",
                    children=(
                        IRNode(
                            kind=IRNodeKind.SUBSECTION,
                            label="1",
                            text="A police authority may obtain any record formerly recalled.",
                        ),
                    ),
                ),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute, adjudications_out=adjudications)
    op = LegalOperation(
        op_id="uk_test_node_local_range_to_end_leaf_patch",
        sequence=0,
        action=StructuralAction.TEXT_REPLACE,
        target=LegalAddress(path=(("section", "3"), ("subsection", "1"))),
        text_patch=TextPatchSpec(
            kind=TextPatchKindEnum.REPLACE,
            selector=TextSelector(match_text="TEXT_FROM_any_TO_END", occurrence=1),
            replacement="the Police Service of Scotland.",
        ),
    )

    executor.apply_op(op)

    subsection = executor.statute.body.children[0].children[0]
    assert subsection.text == "A police authority may obtain the Police Service of Scotland."
    assert not subsection.children
    assert [row.kind for row in adjudications] == [
        "uk_replay_node_local_range_to_end_text_rewrite_applied"
    ]
    assert adjudications[0].detail["blocking"] is False
    assert adjudications[0].detail["strict_disposition"] == "record"
    assert adjudications[0].detail["source_shape"] == "node_local_range_to_end_selector"


def test_compile_range_to_end_second_occurrence_to_text_replace() -> None:
    extracted_el = ET.fromstring(
        f"""
        <P3 xmlns="{_LEG_NS}" id="section-106-2-a">
          <Pnumber>a</Pnumber>
          <Text>a in subsection (1), for the words from “the” where it second occurs to the end substitute “ any of the persons mentioned in subsection (1A) may grant authorisations ” , and</Text>
        </P3>
        """
    )
    effect = UKEffectRecord(
        effect_id="uk_test_range_to_end_second_occurrence",
        effect_type="words substituted",
        applied=True,
        requires_applied=False,
        modified="2011-03-28",
        affected_uri="/id/asp/2000/11",
        affected_class="ScottishAct",
        affected_year="2000",
        affected_number="11",
        affected_provisions="s. 10(1)",
        affecting_uri="/id/asp/2010/13",
        affecting_class="ScottishAct",
        affecting_year="2010",
        affecting_number="13",
        affecting_provisions="s. 106(2)(a)",
        affecting_title="Test Amendment Act",
        in_force_dates=[{"date": "2011-03-28", "prospective": "false"}],
    )

    ops = compile_effect_to_ir_ops(effect, extracted_el, sequence=0)

    assert len(ops) == 1
    assert ops[0].action is StructuralAction.TEXT_REPLACE
    assert ops[0].target.path == (("section", "10"), ("subsection", "1"))
    assert ops[0].text_patch is not None
    assert ops[0].text_patch.kind is TextPatchKindEnum.REPLACE
    assert ops[0].text_patch.selector.match_text == "TEXT_FROM_the_TO_END"
    assert ops[0].text_patch.selector.occurrence == 2
    assert (
        ops[0].text_patch.replacement
        == "any of the persons mentioned in subsection (1A) may grant authorisations"
    )


