def test_compile_multi_quoted_word_repeal_lowers_separate_text_deletes() -> None:
    extracted_el = ET.fromstring(
        f"""
        <P3 xmlns="{_LEG_NS}" id="section-60-8-a">
          <Pnumber>a</Pnumber>
          <P3para>
            <Text>a in subsection (1), the words “or by any other person”, “or other person” and “or any person named in the order” are repealed,</Text>
          </P3para>
        </P3>
        """
    )
    effect = UKEffectRecord(
        effect_id="uk_test_multi_quoted_word_repeal",
        effect_type="words repealed",
        applied=True,
        requires_applied=True,
        modified="2017-04-24",
        affected_uri="/id/asp/2000/4/section/70/subsection/1",
        affected_class="ScottishAct",
        affected_year="2000",
        affected_number="4",
        affected_provisions="s. 70(1)",
        affecting_uri="/id/asp/2007/10/section/60",
        affecting_class="ScottishAct",
        affecting_year="2007",
        affecting_number="10",
        affecting_provisions="s. 60(8)(a)",
        affecting_title="Adult Support and Protection (Scotland) Act 2007",
        in_force_dates=[],
    )
    observations: list[dict[str, Any]] = []

    ops = compile_effect_to_ir_ops(effect, extracted_el, sequence=0, lowering_rejections_out=observations)

    assert [op.action for op in ops] == [
        StructuralAction.TEXT_REPEAL,
        StructuralAction.TEXT_REPEAL,
        StructuralAction.TEXT_REPEAL,
    ]
    assert [str(op.target) for op in ops] == ["section:70/subsection:1"] * 3
    assert [op.text_patch.selector.match_text for op in ops if op.text_patch is not None] == [
        "or by any other person",
        "or other person",
        "or any person named in the order",
    ]
    assert all(op.text_patch is not None and op.text_patch.kind is TextPatchKindEnum.DELETE for op in ops)
    assert [row["rule_id"] for row in observations if row["rule_id"].endswith("_rejected")] == []
    split_rows = [
        row for row in observations if row["rule_id"] == "uk_effect_multi_quoted_word_repeal_text_patches"
    ]
    assert len(split_rows) == 1
    assert split_rows[0]["target"] == "section:70/subsection:1"
    assert split_rows[0]["fragments"] == (
        "or by any other person",
        "or other person",
        "or any person named in the order",
    )


def test_pipeline_compile_ops_blocks_range_to_container_substitution_until_owned(monkeypatch) -> None:
    effect = UKEffectRecord(
        effect_id="uk_test_range_to_container_skip",
        effect_type="substituted for ss. 3-12 and cross-heading",
        applied=True,
        requires_applied=True,
        modified="2024-01-23",
        affected_uri="/id/asp/2001/2",
        affected_class="ScottishAct",
        affected_year="2001",
        affected_number="2",
        affected_provisions="Pt. 2 Ch. 1",
        affecting_uri="/id/asp/2019/17",
        affecting_class="ScottishAct",
        affecting_year="2019",
        affecting_number="17",
        affecting_provisions="s. 35(2)",
        affecting_title="Transport (Scotland) Act 2019",
        in_force_dates=[{"date": "2023-12-04", "prospective": "false"}],
    )
    extracted_el = ET.fromstring(
        f"""
        <P2 xmlns="{_LEG_NS}">
          <Text>For sections 3 to 12 (including the italic heading immediately preceding section 3), substitute—</Text>
          <BlockAmendment>
            <Chapter eId="part-2-chapter-1">
              <Number>Chapter 1</Number>
              <Title>Bus services improvement partnerships</Title>
            </Chapter>
          </BlockAmendment>
        </P2>
        """
    )
    compiled = [
        LegalOperation(
            op_id="uk_test_range_to_container_skip",
            sequence=0,
            action=StructuralAction.REPLACE,
            target=LegalAddress(path=(("part", "2"), ("chapter", "1"))),
            payload=IRNode(
                kind=IRNodeKind.CHAPTER,
                label="1",
                text="Bus services improvement partnerships",
                attrs={"eId": "part-2-chapter-1"},
                children=(
                    IRNode(kind=IRNodeKind.SECTION, label="3A", attrs={"eId": "section-3A"}),
                ),
            ),
            source=OperationSource(statute_id="asp/2001/2", title="Transport (Scotland) Act 2019"),
        )
    ]

    monkeypatch.setattr(
        uk_replay_mod,
        "load_effects_for_statute_from_archive",
        lambda _sid, _archive: [effect],
    )
    monkeypatch.setattr(
        uk_replay_mod,
        "get_affecting_act_xml_from_archive",
        lambda _aid, _archive: _AVAILABLE_XML_BYTES,
    )
    monkeypatch.setattr(
        uk_replay_mod,
        "extract_provision_element_from_bytes",
        lambda _xml, _prov, **_kwargs: extracted_el,
    )
    monkeypatch.setattr(
        uk_replay_mod,
        "compile_effect_to_ir_ops",
        lambda _effect, _el, sequence=0, **_kwargs: compiled,
    )

    lowering_rejections: list[dict[str, Any]] = []
    diagnostics: list[dict[str, Any]] = []

    assert UKReplayPipeline(Path(".")).compile_ops_for_statute(
        "asp/2001/2",
        archive=object(),
        lowering_rejections_out=lowering_rejections,
        effect_diagnostics_out=diagnostics,
    ) == []

    assert lowering_rejections[-1]["rule_id"] == "uk_effect_range_to_container_substitution_rejected"
    assert lowering_rejections[-1]["blocking"] is True
    assert lowering_rejections[-1]["source_pathology"] == "range_to_container_target_unsupported"
    assert lowering_rejections[-1]["source_range_kind"] == "section"
    assert lowering_rejections[-1]["source_range_start"] == "3"
    assert lowering_rejections[-1]["source_range_end"] == "12"
    assert lowering_rejections[-1]["source_range_section_count"] == 10
    assert lowering_rejections[-1]["source_range_sections"] == tuple(
        {"label": str(label), "eid": ""} for label in range(3, 13)
    )
    assert lowering_rejections[-1]["truncated_source_range_sections"] is False
    assert lowering_rejections[-1]["compiled_targets"] == ("part:2/chapter:1",)
    assert lowering_rejections[-1]["payload_roots"] == (
        {
            "kind": "chapter",
            "label": "1",
            "eid": "part-2-chapter-1",
            "direct_child_count": 1,
            "direct_children": (
                {"kind": "section", "label": "3A", "eid": "section-3A"},
            ),
            "truncated_direct_children": False,
            "descendant_section_count": 1,
            "descendant_sections": (
                {"label": "3A", "eid": "section-3A"},
            ),
            "truncated_descendant_sections": False,
        },
    )
    assert lowering_rejections[-1]["required_ownership"] == (
        "source_range",
        "container_payload",
        "lineage_or_migration_events",
        "mutation_boundary",
    )
    manual_rows = [
        row
        for row in diagnostics
        if row["rule_id"] == "uk_manual_compile_frontier_classified"
    ]
    assert manual_rows[-1]["manual_compile_status"] == "manual_compile_candidate"
    assert manual_rows[-1]["manual_compile_rule_id"] == "uk_manual_frontier_range_to_container_candidate"
    assert manual_rows[-1]["lowering_rule_ids"] == (
        "uk_effect_range_to_container_substitution_rejected",
    )
    assert manual_rows[-1]["blocking_lowering_rule_ids"] == (
        "uk_effect_range_to_container_substitution_rejected",
    )


