def test_executor_scopes_schedule_descendant_invariant_scan_to_parent(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    import lawvm.uk_legislation.replay_invariant_diagnostics as invariant_mod

    statute = IRStatute(
        statute_id="ukpga/2000/22",
        title="Test Act",
        body=IRNode(kind=IRNodeKind.BODY, label=None, text="", children=()),
        supplements=(
            IRNode(
                kind=IRNodeKind.SCHEDULE,
                label="1",
                text="",
                attrs={"eId": "schedule-1"},
                children=(
                    IRNode(
                        kind=IRNodeKind.PARAGRAPH,
                        label="1",
                        text="",
                        attrs={"eId": "schedule-1-paragraph-1"},
                        children=(
                            IRNode(
                                kind=IRNodeKind.SUBPARAGRAPH,
                                label="a",
                                text="A.",
                                attrs={"eId": "schedule-1-paragraph-1-a"},
                            ),
                        ),
                    ),
                    IRNode(
                        kind=IRNodeKind.PARAGRAPH,
                        label="2",
                        text="",
                        attrs={"eId": "schedule-1-paragraph-2"},
                    ),
                ),
            ),
        ),
    )
    executor: Any = UKReplayExecutor(statute, adjudications_out=[])
    scanned_roots: list[tuple[str, str | None]] = []

    def collect_scanned_root(root: UKMutableNode, **_kwargs: object) -> list[str]:
        scanned_roots.append((root.kind.value, root.label))
        return []

    monkeypatch.setattr(
        invariant_mod,
        "_collect_duplicate_order_invariants",
        collect_scanned_root,
    )

    executor.apply_op(
        LegalOperation(
            op_id="uk_test_schedule_descendant_parent_scoped_invariant_scan",
            sequence=1,
            action=StructuralAction.INSERT,
            target=LegalAddress(
                path=(("schedule", "1"), ("paragraph", "1"), ("subparagraph", "b"))
            ),
            payload=IRNode(
                kind=IRNodeKind.SUBPARAGRAPH,
                label="b",
                text="B.",
            ),
            source=OperationSource(statute_id="uk_test", title="Test Source"),
        )
    )

    assert scanned_roots == [("paragraph", "1")]
    paragraph = executor.statute.supplements[0].children[0]
    assert [child.label for child in paragraph.children] == ["a", "b"]
    assert executor.adjudications_out == []


def test_executor_skips_repeal_invariant_scan_without_existing_scoped_violation(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    import lawvm.uk_legislation.replay_invariant_diagnostics as invariant_mod

    statute = IRStatute(
        statute_id="ukpga/2000/22",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(kind=IRNodeKind.SECTION, label="1", text="", attrs={"eId": "section-1"}),
                IRNode(kind=IRNodeKind.SECTION, label="2", text="", attrs={"eId": "section-2"}),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute, adjudications_out=[])

    def fail_collect(*_args: object, **_kwargs: object) -> list[str]:
        raise AssertionError("clean removal-only replay cannot create duplicate/order invariants")

    monkeypatch.setattr(
        invariant_mod,
        "_collect_duplicate_order_invariants",
        fail_collect,
    )

    def fail_target_roots(*_args: object, **_kwargs: object) -> list[object]:
        raise AssertionError("clean removal-only replay should not resolve invariant target roots")

    executor._invariant_target_roots_for_op = fail_target_roots
    executor.apply_op(
        LegalOperation(
            op_id="uk_test_clean_repeal_no_invariant_scan",
            sequence=1,
            action=StructuralAction.REPEAL,
            target=LegalAddress(path=(("section", "1"),)),
            source=OperationSource(statute_id="uk_test", title="Test Source"),
        )
    )

    assert [child.label for child in executor.statute.body.children] == ["2"]
    assert executor.adjudications_out == []


def test_executor_rescans_repeal_when_existing_scoped_violation_may_clear(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    import lawvm.uk_legislation.replay_invariant_diagnostics as invariant_mod

    statute = IRStatute(
        statute_id="ukpga/2000/22",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(kind=IRNodeKind.SECTION, label="1", text="", attrs={"eId": "section-1a"}),
                IRNode(kind=IRNodeKind.SECTION, label="1", text="", attrs={"eId": "section-1b"}),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute, adjudications_out=[])
    calls = 0

    def collect_after_repeal(*_args: object, **_kwargs: object) -> list[str]:
        nonlocal calls
        calls += 1
        return []

    monkeypatch.setattr(
        invariant_mod,
        "_collect_duplicate_order_invariants",
        collect_after_repeal,
    )
    executor.apply_op(
        LegalOperation(
            op_id="uk_test_dirty_repeal_rescans_invariants",
            sequence=1,
            action=StructuralAction.REPEAL,
            target=LegalAddress(path=(("section", "1"),)),
            source=OperationSource(statute_id="uk_test", title="Test Source"),
        )
    )

    assert calls == 1
    assert [child.label for child in executor.statute.body.children] == ["1"]
    assert executor.adjudications_out == []


def test_executor_sequence_match_does_not_alias_section_1_1_to_section_11() -> None:
    statute = IRStatute(
        statute_id="ukpga/2000/22",
        title="Test Act",
        body=IRNode(
            kind=IRNodeKind.BODY,
            label=None,
            text="",
            children=(
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="1",
                    text="",
                    attrs={"eId": "section-1"},
                    children=(),
                ),
                IRNode(
                    kind=IRNodeKind.SECTION,
                    label="11",
                    text="",
                    attrs={"eId": "section-11"},
                    children=(),
                ),
            ),
        ),
        supplements=(),
    )
    executor: Any = UKReplayExecutor(statute)
    executor.apply_op(
        LegalOperation(
            op_id="uk_test_insert_section_1_1_a_vi",
            sequence=1,
            action=StructuralAction.INSERT,
            target=LegalAddress(
                path=(
                    ("section", "1"),
                    ("subsection", "1"),
                    ("paragraph", "a"),
                    ("subparagraph", "vi"),
                )
            ),
            payload=IRNode(kind=IRNodeKind.PARAGRAPH, label="a", text="vi inserted text"),
            source=OperationSource(statute_id="ukpga/2000/22", title="Amending Act"),
        )
    )

    section_1, section_11 = executor.statute.body.children
    assert section_1.children == []
    assert section_11.children == []


